					<img v-else class="upload-img" style="margin-right:20px;" v-bind:key="index" v-for="(item,index) in ruleForm.imgurl.split(',')" :src="$base.url+item" width="100" height="100" @click="imgPreView($base.url+item)">
				</el-form-item>
				<el-form-item class="input" v-if="type!='info'"  label="播放量" prop="playcount" >
					<el-input v-model.number="ruleForm.playcount" placeholder="播放量" clearable  :readonly="ro.playcount"></el-input>
				</el-form-item>
				<el-form-item v-else class="input" label="播放量" prop="playcount" >
					<el-input v-model="ruleForm.playcount" placeholder="播放量" readonly></el-input>
				</el-form-item>
				<el-form-item class="input" v-if="type!='info'"  label="作者" prop="author" >
					<el-input v-model="ruleForm.author" placeholder="作者" clearable  :readonly="ro.author"></el-input>
				</el-form-item>
				<el-form-item v-else class="input" label="作者" prop="author" >
					<el-input v-model="ruleForm.author" placeholder="作者" readonly></el-input>
				</el-form-item>
				<el-form-item class="input" v-if="type!='info'"  label="收藏量" prop="favcount" >
					<el-input v-model.number="ruleForm.favcount" placeholder="收藏量" clearable  :readonly="ro.favcount"></el-input>
				</el-form-item>
				<el-form-item v-else class="input" label="收藏量" prop="favcount" >
					<el-input v-model="ruleForm.favcount" placeholder="收藏量" readonly></el-input>
				</el-form-item>
				<el-form-item class="input" v-if="type!='info'"  label="分享量" prop="sharecount" >
					<el-input v-model.number="ruleForm.sharecount" placeholder="分享量" clearable  :readonly="ro.sharecount"></el-input>
				</el-form-item>
				<el-form-item v-else class="input" label="分享量" prop="sharecount" >
					<el-input v-model="ruleForm.sharecount" placeholder="分享量" readonly></el-input>
				</el-form-item>
				<el-form-item class="input" v-if="type!='info'"  label="评论数" prop="commentcount" >
					<el-input v-model.number="ruleForm.commentcount" placeholder="评论数" clearable  :readonly="ro.commentcount"></el-input>
				</el-form-item>
				<el-form-item v-else class="input" label="评论数" prop="commentcount" >
					<el-input v-model="ruleForm.commentcount" placeholder="评论数" readonly></el-input>
				</el-form-item>
				<el-form-item class="input" v-if="type!='info'"  label="歌曲数" prop="songcount" >
					<el-input v-model.number="ruleForm.songcount" placeholder="歌曲数" clearable  :readonly="ro.songcount"></el-input>
				</el-form-item>
				<el-form-item v-else class="input" label="歌曲数" prop="songcount" >
					<el-input v-model="ruleForm.songcount" placeholder="歌曲数" readonly></el-input>
				</el-form-item>
				<el-form-item class="input" v-if="type!='info'"  label="歌单" prop="playlist" >
					<el-input v-model="ruleForm.playlist" placeholder="歌单" clearable  :readonly="ro.playlist"></el-input>
				</el-form-item>
				<el-form-item v-else class="input" label="歌单" prop="playlist" >
					<el-input v-model="ruleForm.playlist" placeholder="歌单" readonly></el-input>
				</el-form-item>
				<el-form-item class="input" v-if="type!='info'"  label="时长" prop="durtime" >
					<el-input v-model="ruleForm.durtime" placeholder="时长" clearable  :readonly="ro.durtime"></el-input>
				</el-form-item>
				<el-form-item v-else class="input" label="时长" prop="durtime" >
					<el-input v-model="ruleForm.durtime" placeholder="时长" readonly></el-input>
				</el-form-item>
			</template>
			<el-form-item class="textarea" v-if="type!='info'" label="介绍" prop="albumdesc" >
				<el-input
					style="min-width: 200px; max-width: 600px;"
					type="textarea"
					:rows="8"
					placeholder="介绍"
					v-model="ruleForm.albumdesc" >
				</el-input>
			</el-form-item>
			<el-form-item v-else-if="ruleForm.albumdesc" label="介绍" prop="albumdesc"  class="textBox">
				<span class="text">{{ruleForm.albumdesc}}</span>
			</el-form-item>
			<el-form-item class="textarea" v-if="type!='info'" label="来源" prop="detailurl" >
				<el-input
					style="min-width: 200px; max-width: 600px;"
					type="textarea"
					:rows="8"
					placeholder="来源"
					v-model="ruleForm.detailurl" >
				</el-input>
			</el-form-item>
			<el-form-item v-else-if="ruleForm.detailurl" label="来源" prop="detailurl"  class="textBox">
				<span class="text">{{ruleForm.detailurl}}</span>
