</template>
<script>
	import { 
		isIntNumer,
	} from "@/utils/validate";
	export default {
		data() {
			var validateIntNumber = (rule, value, callback) => {
				if(!value){
					callback();
				} else if (!isIntNumer(value)) {
					callback(new Error("请输入整数"));
				} else {
					callback();
				}
			};
			return {
				id: '',
				type: '',
			
			
				ro:{
					songname : false,
					songstyle : false,
					singer : false,
					albumtitle : false,
					imgurl : false,
					playcount : false,
					author : false,
					favcount : false,
					sharecount : false,
					commentcount : false,
					songcount : false,
					playlist : false,
					durtime : false,
					albumdesc : false,
					detailurl : false,
					clicktime : false,
					discussnum : false,
					storeupnum : false,
				},
			
				ruleForm: {
					songname: '',
					songstyle: '',
					singer: '',
					albumtitle: '',
					imgurl: '',
					playcount: '',
					author: '',
					favcount: '',
					sharecount: '',
					commentcount: '',
					songcount: '',
					playlist: '',
					durtime: '',
					albumdesc: '',
					detailurl: '',
					clicktime: '',
					discussnum: Number('0'),
					storeupnum: Number('0'),
				},

				rules: {
					songname: [
					],
					songstyle: [
					],
					singer: [
					],
					albumtitle: [
					],
					imgurl: [
					],
					playcount: [
						{ validator: validateIntNumber, trigger: 'blur' },
					],
					author: [
					],
					favcount: [
						{ validator: validateIntNumber, trigger: 'blur' },
					],
					sharecount: [
						{ validator: validateIntNumber, trigger: 'blur' },
					],
					commentcount: [
						{ validator: validateIntNumber, trigger: 'blur' },
					],
					songcount: [
						{ validator: validateIntNumber, trigger: 'blur' },
					],
					playlist: [
					],
					durtime: [
					],
					albumdesc: [
					],
					detailurl: [
					],
					clicktime: [
					],
					discussnum: [
						{ validator: validateIntNumber, trigger: 'blur' },
					],
					storeupnum: [
						{ validator: validateIntNumber, trigger: 'blur' },
					],
				},
			};
		},
		props: ["parent"],
		computed: {
			sessionForm() {
				return JSON.parse(this.$storage.getObj('userForm'))
			},
			sessionTable() {
				return this.$storage.get('sessionTable')
			},



		},
		components: {
		},
		created() {
		},
		methods: {
			imgPreView(url){
				this.$parent.imgPreView(url)
			},
			// 下载
			download(file){
				window.open(`${file}`)
			},
			// 初始化
			init(id,type ) {
				if (id) {
					this.id = id;
					this.type = type;
				}
				if(this.type=='info'||this.type=='else'||this.type=='msg'){
					this.info(id);
				}else if(this.type=='logistics'){
					for(let x in this.ro) {
						this.ro[x] = true
					}
					this.logistics=false;
					this.info(id);
				}else if(this.type=='cross'){
					var obj = this.$storage.getObj('crossObj');
					for (var o in obj){
						if(o=='songname'){
							this.ruleForm.songname = obj[o];
							this.ro.songname = true;
							continue;
						}
						if(o=='songstyle'){
							this.ruleForm.songstyle = obj[o];
							this.ro.songstyle = true;
							continue;
						}
						if(o=='singer'){
							this.ruleForm.singer = obj[o];
							this.ro.singer = true;
							continue;
						}
						if(o=='albumtitle'){
							this.ruleForm.albumtitle = obj[o];
							this.ro.albumtitle = true;
							continue;
						}
						if(o=='imgurl'){
							this.ruleForm.imgurl = obj[o];
							this.ro.imgurl = true;
							continue;
						}
						if(o=='playcount'){
							this.ruleForm.playcount = obj[o];
							this.ro.playcount = true;
							continue;
						}
						if(o=='author'){
							this.ruleForm.author = obj[o];
							this.ro.author = true;
							continue;
						}
						if(o=='favcount'){
							this.ruleForm.favcount = obj[o];
							this.ro.favcount = true;
							continue;
						}
						if(o=='sharecount'){
							this.ruleForm.sharecount = obj[o];
							this.ro.sharecount = true;
							continue;
						}
						if(o=='commentcount'){
							this.ruleForm.commentcount = obj[o];
							this.ro.commentcount = true;
							continue;
						}
						if(o=='songcount'){
							this.ruleForm.songcount = obj[o];
							this.ro.songcount = true;
							continue;
						}
						if(o=='playlist'){
							this.ruleForm.playlist = obj[o];
							this.ro.playlist = true;
							continue;
						}
						if(o=='durtime'){
							this.ruleForm.durtime = obj[o];
							this.ro.durtime = true;
							continue;
						}
						if(o=='albumdesc'){
							this.ruleForm.albumdesc = obj[o];
							this.ro.albumdesc = true;
							continue;
						}
						if(o=='detailurl'){
							this.ruleForm.detailurl = obj[o];
							this.ro.detailurl = true;
							continue;
						}
						if(o=='clicktime'){
							this.ruleForm.clicktime = obj[o];
							this.ro.clicktime = true;
							continue;
						}
						if(o=='discussnum'){
							this.ruleForm.discussnum = obj[o];
							this.ro.discussnum = true;
							continue;
						}
						if(o=='storeupnum'){
							this.ruleForm.storeupnum = obj[o];
							this.ro.storeupnum = true;
							continue;
						}
					}
				}

			
			},
			// 多级联动参数

			async info(id) {
				await this.$http({
					url: `musicinfo/info/${id}`,
					method: "get"
				}).then(({ data }) => {
					if (data && data.code === 0) {
						this.ruleForm = data.data;
						//解决前台上传图片后台不显示的问题
						let reg=new RegExp('../../../upload','g')//g代表全部
					} else {
						this.$message.error(data.msg);
					}
				});
			},

			// 提交
			async onSubmit() {
					await this.$refs["ruleForm"].validate(async valid => {
						if (valid) {
							if(this.ruleForm.imgurl!=null) {
								this.ruleForm.imgurl = this.ruleForm.imgurl.replace(new RegExp(this.$base.url,"g"),"");
							}
							var objcross = this.$storage.getObj('crossObj');
							if(!this.ruleForm.id) {
								delete this.ruleForm.userid
							}
							if(this.type=='cross'){
								var statusColumnName = this.$storage.get('statusColumnName');
								var statusColumnValue = this.$storage.get('statusColumnValue');
								if(statusColumnName!='') {
									var obj = this.$storage.getObj('crossObj');
									if(statusColumnName && !statusColumnName.startsWith("[")) {
										for (var o in obj){
											if(o==statusColumnName){
												obj[o] = statusColumnValue;
											}
										}
										var table = this.$storage.get('crossTable');
										await this.$http({
											url: `${table}/update`,
											method: "post",
											data: obj
										}).then(({ data }) => {});
									}
								}
							}
							await this.$http({
								url: `musicinfo/${!this.ruleForm.id ? "save" : "update"}`,
								method: "post",
								data: this.ruleForm
							}).then(async ({ data }) => {
								if (data && data.code === 0) {
									this.$message({
										message: "操作成功",
										type: "success",
										duration: 1500,
										onClose: () => {
											this.parent.showFlag = true;
											this.parent.addOrUpdateFlag = false;
											this.parent.musicinfoCrossAddOrUpdateFlag = false;
											this.parent.search();
										}
									});
								} else {
									this.$message.error(data.msg);
								}
							});
						}
					});
			},
			// 获取uuid
			getUUID () {
				return new Date().getTime();
			},
			// 返回
			back() {
				this.parent.showFlag = true;
				this.parent.addOrUpdateFlag = false;
				this.parent.musicinfoCrossAddOrUpdateFlag = false;
			},
			imgurlUploadChange(fileUrls) {
				this.ruleForm.imgurl = fileUrls;
			},
		}
	};
</script>
